member.example:
Bind the CanvasGroup ignoreParentGroups property using a serialized binder field — the target CanvasGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CanvasGroupIgnoreParentGroupsBinder _ignoreParentGroups;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _ignoreParentGroups;
    }


Bind the CanvasGroup ignoreParentGroups property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CanvasGroup _canvasGroup;
        
        private CanvasGroupIgnoreParentGroupsBinder IgnoreParentGroups =>
            new(_canvasGroup);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _ignoreParentGroups;
    }
